import React, { useEffect, useState } from "react";

export default function About() {

  const [visible, setVisible] = useState(false);

  useEffect(() => {
    setVisible(true);
  }, []);

  const features = [
    {
      icon: "📍",
      title: "Real-time Tracking",
      desc: "Track your journey live with accurate GPS monitoring.",
    },
    {
      icon: "🚨",
      title: "Emergency Alerts",
      desc: "Instantly notify trusted contacts in danger situations.",
    },
    {
      icon: "👮‍♀️",
      title: "Police Assistance",
      desc: "Find nearby police stations quickly when needed.",
    },
  ];

  return (
    <div className="about-page">

      {/* FLOATING LIGHTS */}
      <div className="bg-glow"></div>

      {/* CONTENT */}
      <div className={`about-container ${visible ? "show" : ""}`}>

        {/* HEADER */}
        <div className="about-header">
          <h1>💖 Women Safety App</h1>
          <p>
            Smart protection with real-time tracking, emergency alerts,
            and AI-based safety monitoring.
          </p>
        </div>

        {/* FEATURES */}
        <div className="about-features">

          {features.map((f, i) => (
            <div key={i} className="about-card">

              <div className="icon">{f.icon}</div>

              <h3>{f.title}</h3>

              <p>{f.desc}</p>

            </div>
          ))}

        </div>

        {/* EXTRA SECTION (APP FEEL) */}
        <div className="about-footer">
          <p>
            Your safety is our priority. Stay connected, stay protected 💖
          </p>
        </div>

      </div>

    </div>
  );
}
